import javahttp from "@/assets/js/javahttp"
// 轮播图
function getBanner(){
  return new Promise((resolve,reject)=>{
    javahttp.get('/music/banner').then(resolve).catch(reject)
  })
}
// 推荐歌单
function getRecommend(data){
  return new Promise((resolve,reject)=>{
    javahttp.get('/music/personalized',data).then(resolve).catch(reject)
  })
}
